I been trying to get my BME280 Temperature Sensor connected with Homie.  Everything works great.  Except when I apply the working code that is reading the BME280 values, the values all come back null. 

If I remove the homie references, values print nicely on the serial.

What am I doing wrong

```
#include "Wire.h"
#include "BME280.h"
#include "Homie.h"

#define FW_NAME "temp"
#define FW_VERSION "1.0.0"

BME280 bme;
bool metric = false;

HomieNode temperatureNode("temperature", "temperature");
HomieNode humidityNode("humidity", "humidity");
HomieNode pressureNode("pressure", "pressure");
HomieNode altitudeNode("altitude", "altitude");
HomieNode dewpointNode("dewpoint", "dewpoint");

const int SEND_INTERVAL = 60;
unsigned long lastDataSent = 0;

void loopHandler() {
  if (millis() - lastDataSent >= SEND_INTERVAL * 1000UL || lastDataSent == 0) {
    float temp(NAN), hum(NAN), pres(NAN);
    uint8_t pressureUnit(2);   // unit: B000 = Pa, B001 = hPa, B010 = Hg, B011 = atm, B100 = bar, B101 = torr, B110 = N/m^2, B111 = psi
    bme.ReadData(pres, temp, hum, metric, pressureUnit);                // Parameters: (float& pressure, float& temp, float& humidity, bool hPa = true, bool celsius = false)

    Serial.print("Temp: ");
    Serial.print(temp);
    Serial.print("°"+ String(metric ? 'C' :'F'));
    Serial.print("\t\tHumidity: ");
    Serial.print(hum);
    Serial.print("% RH");
    Serial.print("\t\tPressure: ");
    Serial.print(pres);
    Serial.print(" atm");

    float altitude = bme.CalculateAltitude(metric);
    float dewPoint = bme.CalculateDewPoint(metric);
    Serial.print("\t\tAltitude: ");
    Serial.print(altitude);
    Serial.print((metric ? "m" : "ft"));
    Serial.print("\t\tDew point: ");
    Serial.print(dewPoint);
    Serial.println("°"+ String(metric ? 'C' :'F'));

    Homie.setNodeProperty(temperatureNode, "degrees").send(String(temp));
    Homie.setNodeProperty(humidityNode, "relative").send(String(hum));
    Homie.setNodeProperty(pressureNode, "atm").send(String(pres));
    Homie.setNodeProperty(altitudeNode, "ft").send(String(altitude));
    Homie.setNodeProperty(dewpointNode, "degrees").send(String(dewPoint));

    lastDataSent = millis();
  }
}

void setupHandler() {

  Homie.setNodeProperty(temperatureNode, "unit").setRetained(true).send("f");  
  Homie.setNodeProperty(humidityNode, "unit").setRetained(true).send("%");  
  Homie.setNodeProperty(pressureNode, "unit").setRetained(true).send("atm");  
  Homie.setNodeProperty(altitudeNode, "unit").setRetained(true).send("ft");  
  Homie.setNodeProperty(dewpointNode, "unit").setRetained(true).send("f");

  temperatureNode.advertise("degrees");
  temperatureNode.advertise("unit");
  humidityNode.advertise("relative");
  humidityNode.advertise("unit");
  pressureNode.advertise("atm");
  pressureNode.advertise("unit");
  altitudeNode.advertise("ft");
  altitudeNode.advertise("unit");
  dewpointNode.advertise("degrees");
  dewpointNode.advertise("unit");

}

void setup() {
  Serial.begin(115200);
  Wire.begin(0,2);         
  while(!Serial) {} // Wait
  while(!bme.begin()){
    Serial.println("Could not find BME280 sensor!");
    delay(1000);
  }

  Homie_setFirmware(FW_NAME, FW_VERSION);
  Homie.setSetupFunction(setupHandler).setLoopFunction(loopHandler);

  Homie.setup();
}

void loop() {
  Homie.loop();
}
```

**Update:** After further investigation, it seems that inside the loopHandler, Homie is no longer able to see i2c devices.  Starting up with BME280 debug to make sure it gets find on setup, everything looks good. putting the i2c scanner from the Wire.h library inside the Homie loop and it no longer works.

```
byte error, address;
int nDevices;

Serial.println("Scanning...");

nDevices = 0;
for(address = 1; address < 127; address++ )
{
// The i2c_scanner uses the return value of
// the Write.endTransmisstion to see if
// a device did acknowledge to the address.
Wire.beginTransmission(address);
error = Wire.endTransmission();

if (error == 0)
{
Serial.print("I2C device found at address 0x");
if (address<16)
Serial.print("0");
Serial.print(address,HEX);
Serial.println(" !");

nDevices++;
}
else if (error==4)
{
Serial.print("Unknow error at address 0x");
if (address<16)
Serial.print("0");
Serial.println(address,HEX);
} 
}
if (nDevices == 0)
Serial.println("No I2C devices found\n");
else
Serial.println("done\n");
```

On a regular loop(), I2C devices are found.

