### Problem

See #1936 

### Solution

- Open the socket for DNS Client and keep it open, do not close it.
- If the socket send fails, retry once after closing and reopening the socket.
- If the socket send fails a second time, close the socket and return the error.
- Changes polling of socket for pending data to using URCs to indicate pending data with `socketReadable()`
- Automatic socket/handle cleanup on creation of sockets
- Detects state mismatch between system and modem and invalidates DNS Client sock_ handle and also reinitializing mdm_hal sockets[] state
- Removes log noise by closing only untracked socket handles that are open [ch37610]
- Increases USOCO timeout to 130s based on observation that 120s timeout is not being respected by u-blox modem when the command results in CME ERROR.

### Steps to Test

See #1936 and additional tests in app below

### Firmware from this PR (built against 1.4.1-rc.1)
⬇️ [particle-device-os@1.4.1-rc.1+debug.pr1938.zip](https://www.dropbox.com/s/ri3od0yht8fnxe3/particle-device-os%401.4.1-rc.1%2Bdebug.pr1938.zip?dl=0)

### Test app

```c++
#include "Particle.h"
#include "socket_hal.h"
SerialLogHandler logHandler(LOG_LEVEL_ALL);
SYSTEM_MODE(SEMI_AUTOMATIC);
system_tick_t lastDNSLookup = 0;

void setup() {
    pinMode(B1, INPUT_PULLUP);
    pinMode(B2, INPUT_PULLUP);
    pinMode(B3, INPUT_PULLUP);
    Particle.connect();
    waitUntil(Particle.connected);

    // Open a TCP socket just to test
    Serial.println("\r\n\r\nOPEN TCP SOCKET =====================================");
    int port = 80;
    socket_create(AF_INET, SOCK_STREAM, IPPROTO_TCP, port, NIF_DEFAULT);
}

void loop()
{
    if (millis() - lastDNSLookup >= 10000UL) {
        Serial.println("\r\n\r\nDNS lookup =====================================");
        Cellular.command("AT+CCLK?\r\n"); // timestamp
        IPAddress ip = Cellular.resolve("google.com");

        while (digitalRead(B3) == LOW); // Pull antenna and wait for AT command failure before continuing
        // Checks DNS Client & Modem state mismatch

        Particle.publish("Google HOST IP", String(ip), PRIVATE, NO_ACK);
        lastDNSLookup = millis();

        // Check return path after DNS failure
        if (digitalRead(B1) == LOW) {
            Particle.publish("Google HOST IP", String(ip), PRIVATE, WITH_ACK);
            while (digitalRead(B1) == LOW) Particle.process();
            delay(100);
        }

        // Checks DNS Client & Modem state mismatch
        if (digitalRead(B2) == LOW) {
            Cellular.off();
            Cellular.on();
            delay(100);
            while (digitalRead(B2) == LOW) Particle.process();
            delay(100);
        }

        // press RESET to check MCU / DNS Client & Modem state mismatch
    }
}
```

